modules.fpm_unpack:
`timescale 1ns/1ps
module fpm_unpack(
    input  [31:0] a,
    input  [31:0] b,
    output        a_sign,
    output [7:0]  a_exp,
    output [23:0] a_mant,
    output        b_sign,
    output [7:0]  b_exp,
    output [23:0] b_mant,
    output        a_is_nan,
    output        a_is_inf,
    output        a_is_zero,
    output        b_is_nan,
    output        b_is_inf,
    output        b_is_zero
);
    // Unpack a
    assign a_sign = a[31];
    assign a_exp = a[30:23];
    wire [22:0] a_mant_frac = a[22:0];

    // Determine a special cases
    assign a_is_zero = (a_exp == 8'b0) && (a_mant_frac == 23'b0);
    assign a_is_inf = (a_exp == 8'hFF) && (a_mant_frac == 23'b0);
    assign a_is_nan = (a_exp == 8'hFF) && (a_mant_frac != 23'b0);

    // Build a mantissa with implicit 1 for normalized numbers
    // For normalized (exp != 0): mant = 1.mant_frac (24 bits, implicit 1 in bit 23)
    // For denormal (exp == 0): mant = 0.mant_frac (24 bits, no implicit 1)
    assign a_mant = (a_exp == 8'b0) ? {1'b0, a_mant_frac} : {1'b1, a_mant_frac};

    // Unpack b
    assign b_sign = b[31];
    assign b_exp = b[30:23];
    wire [22:0] b_mant_frac = b[22:0];

    // Determine b special cases
    assign b_is_zero = (b_exp == 8'b0) && (b_mant_frac == 23'b0);
    assign b_is_inf = (b_exp == 8'hFF) && (b_mant_frac == 23'b0);
    assign b_is_nan = (b_exp == 8'hFF) && (b_mant_frac != 23'b0);

    // Build b mantissa with implicit 1 for normalized numbers
    assign b_mant = (b_exp == 8'b0) ? {1'b0, b_mant_frac} : {1'b1, b_mant_frac};

endmodule

modules.fpm_multiply:
`timescale 1ns/1ps
module fpm_multiply(
    input         a_sign,
    input  [7:0]  a_exp,
    input  [23:0] a_mant,
    input         b_sign,
    input  [7:0]  b_exp,
    input  [23:0] b_mant,
    output        result_sign,
    output [47:0] product,
    output [9:0]  raw_exp
);
    // Sign is XOR of input signs
    assign result_sign = a_sign ^ b_sign;

    // Product of mantissas (24-bit × 24-bit = 48-bit)
    assign product = a_mant * b_mant;

    // Raw exponent: sum of exponents minus bias (127)
    // a_exp + b_exp - 127, but we need to handle the range
    // Result is 10 bits to accommodate values up to 254+254-127=381
    assign raw_exp = {2'b0, a_exp} + {2'b0, b_exp} - 10'd127;

endmodule

modules.fpm_normalize:
`timescale 1ns/1ps
module fpm_normalize(
    input  [47:0] product,
    input  [9:0]  raw_exp,
    output [22:0] norm_frac,
    output [9:0]  norm_exp,
    output        guard,
    output        sticky
);
    assign norm_frac = 0;
    assign norm_exp  = 0;
    assign guard     = 0;
    assign sticky    = 0;
endmodule

modules.fpm_round_pack:
`timescale 1ns/1ps
module fpm_round_pack(
    input         sign,
    input  [22:0] norm_frac,
    input  [9:0]  norm_exp,
    input         guard,
    input         sticky,
    output reg [31:0] result,
    output reg        overflow,
    output reg        underflow
);

    always @(*) begin
        reg [22:0] rounded_frac;
        reg [9:0] rounded_exp;
        reg round_bit;

        // Determine rounding: round up if (guard & (sticky | frac[0]))
        round_bit = guard & (sticky | norm_frac[0]);

        // Add rounding
        if (round_bit) begin
            rounded_frac = norm_frac + 1;
        end else begin
            rounded_frac = norm_frac;
        end

        // Handle mantissa overflow from rounding
        rounded_exp = norm_exp;
        if (rounded_frac[22] == 0 && round_bit == 1 && norm_frac == 23'h7FFFFF) begin
            // Mantissa overflowed to 24 bits, need to increment exponent
            rounded_exp = norm_exp + 1;
            rounded_frac = 23'h0;
        end

        // Check for underflow and overflow
        underflow = (rounded_exp == 10'd0);
        overflow = (rounded_exp >= 10'd255);

        // Pack the result
        if (underflow) begin
            result = {sign, 31'h0};
            overflow = 1'b0;
        end else if (overflow) begin
            result = {sign, 8'hFF, 23'h0};
            underflow = 1'b0;
        end else begin
            result = {sign, rounded_exp[7:0], rounded_frac[22:0]};
            overflow = 1'b0;
            underflow = 1'b0;
        end
    end

endmodule

modules.fpm_special:
`timescale 1ns/1ps
module fpm_special(
    input         a_is_nan,
    input         a_is_inf,
    input         a_is_zero,
    input         b_is_nan,
    input         b_is_inf,
    input         b_is_zero,
    input         result_sign,
    output        is_special,
    output reg [31:0] special_result
);

    // is_special is 1 if any operand is NaN, Inf, or Zero
    assign is_special = a_is_nan | a_is_inf | a_is_zero | b_is_nan | b_is_inf | b_is_zero;

    always @(*) begin
        // Default: normal case (should not reach here if is_special=0)
        special_result = 32'h0;

        // NaN cases: if either operand is NaN, result is NaN
        if (a_is_nan | b_is_nan) begin
            special_result = 32'h7FC00000;  // Quiet NaN
        end
        // Inf × 0 or 0 × Inf → NaN (invalid operation)
        else if ((a_is_inf & b_is_zero) | (a_is_zero & b_is_inf)) begin
            special_result = 32'h7FC00000;  // NaN
        end
        // Inf × non-zero → Inf with sign
        else if (a_is_inf | b_is_inf) begin
            special_result = {result_sign, 31'h7F800000};
        end
        // 0 × non-zero → signed zero
        else if (a_is_zero | b_is_zero) begin
            special_result = {result_sign, 31'h0};
        end
    end

endmodule
